/** biome-ignore-all lint/suspicious/noConsole: test setup logging */
import { canUseDOM } from '@chakra-ui/utils';
import matchers from '@testing-library/jest-dom/matchers';
import { cleanup } from '@testing-library/react';
import { server } from '@testUtils/mswServer';
import i18n from 'i18next';
import { initReactI18next } from 'react-i18next';
import { afterAll, afterEach, beforeAll, expect, vi } from 'vitest';

// extend vitest's expect with the extra jest matchers
// from testing-library
expect.extend(matchers);

i18n.use(initReactI18next).init({
  lng: 'en',
  fallbackLng: 'en',

  // have a common namespace used around the full app
  ns: ['translations'],
  defaultNS: 'translations',

  resources: { en: { translations: {} } },
});

const HTMLCanvasElementMock = vi.fn(() => {
  return { prototype: { getContext: vi.fn() } };
});

const mockGlobal = () => {
  // mock user cookie
  Object.defineProperty(window.document, 'cookie', {
    value: `userId=1`,
    writable: true,
  });

  Object.defineProperty(window, 'matchMedia', {
    value: vi.fn().mockImplementation((query) => ({
      matches: false,
      media: query,
      onchange: null,
      addListener: vi.fn(), // deprecated
      removeListener: vi.fn(), // deprecated
      addEventListener: vi.fn(),
      removeEventListener: vi.fn(),
      dispatchEvent: vi.fn(),
    })),
    writable: true,
  });

  // This fixes undefined warnings testing @uiw/react-codemirror
  Object.defineProperty(window.document, 'createRange', {
    value: () => {
      const range = new Range();

      range.getBoundingClientRect = vi.fn();

      range.getClientRects = vi.fn(() => ({
        item: () => null,
        length: 0,
        [Symbol.iterator]: vi.fn(),
      }));

      range.setStart = vi.fn();
      range.setEnd = vi.fn();

      return range;
    },
    writable: true,
  });

  vi.stubGlobal('HTMLCanvasElement', HTMLCanvasElementMock);
};

beforeAll(() => {
  // only mock globals if it's a browser-like DOM
  // (we don't want globals for `node` environments)
  if (canUseDOM()) {
    mockGlobal();

    // Establish API mocking before all tests.
    server.listen({
      onUnhandledRequest: 'error',
    });
  }
});

afterEach(() => {
  // Reset any request handlers that we may add during the tests,
  // so they don't affect other tests.
  if (canUseDOM()) {
    server.resetHandlers();
  }

  cleanup();
});

// Clean up after the tests are finished.
afterAll(() => {
  if (canUseDOM()) {
    server.close();
  }
});

// FAIL LOUDLY on unhandled promise rejections / errors
process.on('unhandledRejection', (reason) => {
  console.log(`FAILED TO HANDLE PROMISE REJECTION`);
  throw reason;
});
